 1	import { FC, useCallback, useState } from 'react';
 2	
 3	import { YellowExclamationTriangleIcon } from '@openshift-console/dynamic-plugin-sdk';
 4	import {
 5	  ActionList,
 6	  ActionListItem,
 7	  Button,
 8	  Flex,
 9	  FlexItem,
10	  Icon,
11	  Label,
12	  Modal,
13	  ModalVariant,
14	  Title
15	} from '@patternfly/react-core';
16	import { CheckCircleIcon, ExclamationCircleIcon, InProgressIcon } from '@patternfly/react-icons';
17	import { TFunction } from 'react-i18next';
18	
19	import { SiteView } from '../../../interfaces/REST.interfaces';
20	import DeleteSiteButton from '../../components/DeleteSiteButton';
21	import { ImportForm } from '../../components/forms/ImportForm';
22	
23	const Header: FC<{ site: SiteView | undefined; t: TFunction }> = function ({ site, t }) {
24	  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
25	
26	  const handleImportOpen = useCallback(() => {
27	    setIsImportModalOpen(true);
28	  }, []);
29	
30	  const handleImportClose = useCallback(() => {
31	    setIsImportModalOpen(false);
32	  }, []);
33	
34	  return (
35	    <Flex style={{ width: '100%' }} justifyContent={{ default: 'justifyContentSpaceBetween' }}>
36	      <FlexItem>
37	        <Flex>
38	          <FlexItem>
39	            <Title headingLevel="h1">{t('Site settings')}</Title>
40	          </FlexItem>
41	          {!site?.status && (
42	            <Label>
43	              <Icon isInline>{<InProgressIcon />}</Icon> {t('In progress')}
44	            </Label>
45	          )}
46	          {!!site?.status && (
47	            <Label>
48	              {!!site?.hasError && (
49	                <Icon isInline status="danger" data-testid="header-error">
50	                  <ExclamationCircleIcon />
51	                </Icon>
52	              )}
53	              {!site?.hasError && !!site?.isConfigured && !!site?.isReady && (
54	                <Icon status="success" data-testid="header-success">
55	                  <CheckCircleIcon />
56	                </Icon>
57	              )}
58	              {'  '} {site?.status} {'  '}
59	              {!site?.hasError && site?.hasSecondaryErrors && (
60	                <Icon status="warning">{<YellowExclamationTriangleIcon />}</Icon>
61	              )}
62	            </Label>
63	          )}
64	        </Flex>
65	      </FlexItem>
66	      {site?.name && (
67	        <FlexItem>
68	          <ActionList>
69	            <ActionListItem>
70	              <Button onClick={handleImportOpen}>{t('Import')}</Button>
71	            </ActionListItem>
72	            <ActionListItem>
73	              <DeleteSiteButton id={site.name} />
74	            </ActionListItem>
75	          </ActionList>
76	        </FlexItem>
77	      )}
78	
79	      <Modal
80	        hasNoBodyWrapper
81	        isOpen={isImportModalOpen}
82	        variant={ModalVariant.large}
83	        showClose={false}
84	        aria-label="import-modal"
85	      >
86	        <ImportForm onSubmit={handleImportClose} />
87	      </Modal>
88	    </Flex>
89	  );
90	};
91	
92	export default Header;

